fun greetPerson(name: String) {
    println("Hello, $name!")
}

fun main() {
    greetPerson("Alice") // Passes "Alice"
    greetPerson("Bob")   // Passes "Bob"
}

fun printPlayerScore(name: String, score: Int) {
    println("Player $name has $score points.")
}

fun main() {
    printPlayerScore("Charlie", 500)
}
